# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os
from typing import Dict, Any, List

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Database connection parameters
    db_config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME'],
        'port': int(os.environ.get('DB_PORT', 3306)),
        'charset': 'utf8mb4'
    }
    
    # Initialize connection
    connection = None
    try:
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Parse query parameters
        query_params = event.get('queryStringParameters', {})
        if not query_params:
            query_params = {}
        
        # Build dynamic SQL query
        sql = "SELECT * FROM products WHERE 1=1"
        params = []
        
        # Handle search term
        search_term = query_params.get('search')
        if search_term:
            sql += " AND (name LIKE %s OR description LIKE %s)"
            params.extend([f"%{search_term}%", f"%{search_term}%"])
        
        # Handle category
        category = query_params.get('category')
        if category:
            sql += " AND category = %s"
            params.append(category)
        
        # Handle price range
        min_price = query_params.get('min_price')
        max_price = query_params.get('max_price')
        if min_price is not None:
            sql += " AND price >= %s"
            params.append(float(min_price))
        if max_price is not None:
            sql += " AND price <= %s"
            params.append(float(max_price))
        
        # Handle sort parameters
        sort_by = query_params.get('sort_by', 'name')
        sort_order = query_params.get('sort_order', 'ASC')
        if sort_by in ['name', 'price', 'category'] and sort_order.upper() in ['ASC', 'DESC']:
            sql += f" ORDER BY {sort_by} {sort_order.upper()}"
        
        # Handle pagination
        page = int(query_params.get('page', 1))
        per_page = int(query_params.get('per_page', 10))
        offset = (page - 1) * per_page
        sql += " LIMIT %s OFFSET %s"
        params.extend([per_page, offset])
        
        # Execute query
        cursor.execute(sql, params)
        results = cursor.fetchall()
        
        # Get total count for pagination info
        count_sql = "SELECT COUNT(*) as total FROM products WHERE 1=1"
        count_params = []
        
        if search_term:
            count_sql += " AND (name LIKE %s OR description LIKE %s)"
            count_params.extend([f"%{search_term}%", f"%{search_term}%"])
        
        if category:
            count_sql += " AND category = %s"
            count_params.append(category)
        
        if min_price is not None:
            count_sql += " AND price >= %s"
            count_params.append(float(min_price))
        
        if max_price is not None:
            count_sql += " AND price <= %s"
            count_params.append(float(max_price))
        
        cursor.execute(count_sql, count_params)
        total_count = cursor.fetchone()['total']
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'pagination': {
                    'page': page,
                    'per_page': per_page,
                    'total': total_count,
                    'pages': (total_count + per_page - 1) // per_page
                }
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': str(e)
            })
        }
    finally:
        if connection:
            connection.close()